+   一、文档布局
+   ============================================================ */
+*{margin:0;padding:0;box-sizing:border-box;}
+:root{
+  --bg:#f5f5f8;--card-bg:#fff;--text:#2d2d3a;--text2:#666;--text3:#999;
+  --border:#e8e8ed;--accent:#ff5a8a;--accent2:#b66dff;--gold:#ffd75e;
+  --sidebar-bg:#1a0d2e;--sidebar-text:#bbb;--sidebar-active:#ff5a8a;
+  --highlight:rgba(255,90,138,.15);
+}
+body.dark{
+  --bg:#1a1a2e;--card-bg:#252540;--text:#e0e0e0;--text2:#aaa;--text3:#777;
+  --border:#333350;--sidebar-bg:#0d0618;
+}
+html{scroll-behavior:smooth;}
+body{font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif;background:var(--bg);color:var(--text);line-height:1.5;font-size:14px;display:flex;min-height:100vh;}
+
+/* 侧边栏 */
+aside.sidebar{width:250px;background:var(--sidebar-bg);color:var(--sidebar-text);flex-shrink:0;position:sticky;top:0;height:100vh;overflow-y:auto;z-index:10;display:flex;flex-direction:column;}
+aside.sidebar::-webkit-scrollbar{width:4px;}
+aside.sidebar::-webkit-scrollbar-thumb{background:rgba(255,255,255,.15);border-radius:2px;}
+.sidebar-header{padding:20px 16px;border-bottom:1px solid rgba(255,255,255,.08);}
+.sidebar-header h1{font-size:18px;font-weight:800;color:#ff5a8a;background:linear-gradient(135deg,#ff5a8a,#b66dff);-webkit-background-clip:text;background-clip:text;color:transparent;}
+.sidebar-header .ver{font-size:11px;color:rgba(255,255,255,.4);margin-top:2px;}
+.sidebar-nav{flex:1;overflow-y:auto;padding:8px 0;}
+.nav-group{margin-bottom:4px;}
+.nav-group-title{padding:10px 16px 4px;font-size:10px;text-transform:uppercase;color:rgba(255,255,255,.3);font-weight:700;letter-spacing:1px;}
+.nav-item{display:flex;align-items:center;padding:8px 16px;cursor:pointer;transition:all .15s;font-size:13px;gap:8px;color:rgba(255,255,255,.6);text-decoration:none;}
+.nav-item:hover{color:#fff;background:rgba(255,255,255,.05);}
+.nav-item.active{color:#ff5a8a;background:rgba(255,90,138,.12);font-weight:600;}
+.nav-item .num{font-size:10px;background:rgba(255,255,255,.12);width:20px;height:20px;display:inline-flex;align-items:center;justify-content:center;border-radius:50%;flex-shrink:0;}
+.sidebar-footer{padding:12px 16px;border-top:1px solid rgba(255,255,255,.08);}
+.sidebar-footer a{color:rgba(255,255,255,.4);font-size:11px;text-decoration:none;}
+
+/* 工具栏 */
+.toolbar{position:sticky;top:0;z-index:20;background:var(--card-bg);border-bottom:1px solid var(--border);padding:12px 20px;display:flex;gap:12px;align-items:center;flex-wrap:wrap;}
+.toolbar .search-box{flex:1;min-width:200px;max-width:360px;display:flex;align-items:center;background:var(--bg);border-radius:8px;padding:8px 12px;gap:8px;}
+.toolbar .search-box input{border:none;background:none;font-size:13px;color:var(--text);width:100%;outline:none;}
+.toolbar .search-box input::placeholder{color:var(--text3);}
+.toolbar .search-box .icon{color:var(--text3);font-size:14px;}
+.toolbar .btn-sm{padding:6px 14px;border-radius:6px;border:1px solid var(--border);background:var(--card-bg);color:var(--text2);font-size:12px;cursor:pointer;white-space:nowrap;}
+.toolbar .btn-sm:hover{background:var(--bg);}
+.toolbar .btn-sm.active{background:var(--accent);color:#fff;border-color:var(--accent);}
+.toolbar .result-count{font-size:12px;color:var(--text3);white-space:nowrap;}
+
+/* 主内容 */
+main.content{flex:1;overflow-y:auto;min-width:0;}
+main.content::-webkit-scrollbar{width:6px;}
+main.content::-webkit-scrollbar-thumb{background:rgba(0,0,0,.15);border-radius:3px;}
+
+/* 面板容器：原型图(左) + 标注表(右) */
+.screen-section{padding:24px 20px 32px;border-bottom:1px solid var(--border);}
+.screen-section.hidden{display:none;}
+.screen-section.highlight-section{background:var(--highlight);}
+.screen-header{display:flex;align-items:center;gap:12px;margin-bottom:18px;}
+.screen-header .num-badge{width:32px;height:32px;border-radius:50%;background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;display:inline-flex;align-items:center;justify-content:center;font-weight:700;font-size:14px;flex-shrink:0;}
+.screen-header h2{font-size:20px;font-weight:800;color:var(--text);}
+.screen-header .route{font-size:11px;color:var(--text3);background:var(--bg);padding:3px 8px;border-radius:4px;font-family:monospace;}
+.screen-panel{display:flex;gap:24px;align-items:flex-start;}
+.panel-left{width:375px;flex-shrink:0;position:sticky;top:68px;}
+
+/* 手机壳 */
+.phone-shell{width:375px;height:812px;background:#fff;border-radius:42px;box-shadow:0 20px 60px rgba(0,0,0,.2),0 0 0 10px #222 inset,0 0 0 14px #1a1a2e;position:relative;overflow:hidden;}
+.phone-shell::before{content:"";position:absolute;top:8px;left:50%;transform:translateX(-50%);width:120px;height:26px;background:#111;border-radius:0 0 16px 16px;z-index:100;}
+.screen-inner{width:100%;height:100%;background:linear-gradient(180deg,#fef6f9 0%,#f3eaff 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}
+
+/* 状态栏 */
+.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:12px;font-weight:600;color:#2d2d3a;flex-shrink:0;}
+.status-bar .icons{display:flex;gap:4px;align-items:center;font-size:10px;}
+.status-bar.dark{color:#fff;}
+/* 导航条 */
+.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:#fff;flex-shrink:0;}
+.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:20px;color:#2d2d3a;}
+.nav-bar .title{font-size:16px;font-weight:700;color:#2d2d3a;flex:1;text-align:center;}
+.nav-bar .right{min-width:32px;font-size:13px;color:#666;text-align:right;}
+/* Tab Bar */
+.tab-bar{height:58px;display:flex;background:#fff;border-top:1px solid #f0f0f5;flex-shrink:0;}
+.tab-bar .ti{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;color:#999;font-size:10px;gap:2px;}
+.tab-bar .ti .ico{font-size:20px;}
+.tab-bar .ti.active{color:#ff5a8a;font-weight:600;}
+/* 内容滚动区 */
+.scroll-content{flex:1;overflow-y:auto;}
+.scroll-content::-webkit-scrollbar{display:none;}
+
+/* 通用组件 */
+.btn{display:inline-flex;align-items:center;justify-content:center;height:42px;padding:0 20px;border-radius:21px;font-size:14px;font-weight:600;background:linear-gradient(135deg,#ff5a8a 0%,#b66dff 100%);color:#fff;box-shadow:0 4px 14px rgba(255,90,138,.3);cursor:default;}
+.btn.block{width:100%;}
+.btn.gold{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;box-shadow:0 4px 14px rgba(255,154,60,.3);}
+.btn.ghost{background:#fff;color:#ff5a8a;border:1.5px solid #ff5a8a;box-shadow:none;}
+.btn.small{height:30px;padding:0 12px;border-radius:15px;font-size:12px;}
+.av{width:44px;height:44px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:16px;}
+.av-1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
+.av-2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
+.av-3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
+.av-4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
+.av-5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
+.av-6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
+.av-7{background:linear-gradient(135deg,#ff9a3c,#ff3b5c);}
+.av-8{background:linear-gradient(135deg,#7c5aff,#ff5a8a);}
+.card{background:#fff;border-radius:12px;padding:12px;box-shadow:0 4px 12px rgba(0,0,0,.04);}
+.tag{display:inline-flex;align-items:center;padding:2px 8px;border-radius:10px;font-size:10px;font-weight:500;background:#fef0f5;color:#ff5a8a;}
+.tag.vip{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;font-weight:700;}
+.tag.gold{background:#fff5d6;color:#ff9a3c;}
+.badge{display:inline-flex;align-items:center;justify-content:center;min-width:16px;height:16px;padding:0 4px;background:#ff3b5c;color:#fff;font-size:9px;font-weight:700;border-radius:8px;}
+.badge.dot{min-width:7px;height:7px;padding:0;border-radius:50%;}
+
+/* 标注面板 */
+.panel-right{flex:1;min-width:0;max-width:640px;}
+.annot-table{width:100%;border-collapse:collapse;font-size:12px;background:var(--card-bg);border-radius:10px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.04);}
+.annot-table thead{background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;}
+.annot-table th{padding:10px 8px;text-align:left;font-weight:600;font-size:11px;white-space:nowrap;}
+.annot-table th:first-child{width:32px;text-align:center;}
+.annot-table td{padding:8px;border-bottom:1px solid var(--border);vertical-align:top;}
+.annot-table tbody tr{cursor:default;transition:background .15s;}
+.annot-table tbody tr:hover{background:rgba(255,90,138,.06);}
+.annot-table tbody tr.row-highlight{background:rgba(255,90,138,.15)!important;outline:2px solid var(--accent);outline-offset:-2px;}
+.annot-table .el-num{text-align:center;font-weight:700;color:var(--accent);font-size:11px;width:32px;}
+.annot-table .el-name{font-weight:600;white-space:nowrap;font-size:12px;}
+.annot-table .el-type{font-size:10px;}
+.annot-table .el-type span{display:inline-block;padding:1px 6px;border-radius:8px;font-weight:600;}
+.el-type-btn{background:#fef0f5;color:#ff5a8a;}
+.el-type-input{background:#f0f4ff;color:#4a6cf7;}
+.el-type-text{background:#f5f5f8;color:#666;}
+.el-type-icon{background:#f3eaff;color:#7c5aff;}
+.el-type-sel{background:#e8fbef;color:#22c55e;}
+.el-type-sw{background:#fff5d6;color:#ff9a3c;}
+.annot-table .el-desc{line-height:1.5;color:var(--text2);}
+.annot-table .el-action{font-size:11px;color:var(--text3);line-height:1.4;}
+.annot-table .el-vip{font-size:10px;text-align:center;}
+.annot-table .vip-only{color:#ff9a3c;font-weight:700;}
+.annot-table .vip-free{color:#4ade80;}
+
+/* 元素高亮标记 */
+.el-highlight{position:relative;}
+.el-highlight::after{content:"";position:absolute;inset:-3px;border:2px solid var(--accent);border-radius:inherit;animation:highlightPulse .8s ease-in-out infinite;pointer-events:none;}
+@keyframes highlightPulse{0%,100%{opacity:1;}50%{opacity:.3;}}
+
+/* ============================================================
+   二、各屏幕专属样式（精简复用自 app.html）
+   ============================================================ */
+
+/* ① 登录页 */
+.login-page{padding:28px 24px;display:flex;flex-direction:column;height:100%;}
+.login-page .logo{font-size:40px;text-align:center;margin-top:40px;}
+.login-page h1{font-size:28px;font-weight:800;text-align:center;margin-top:10px;background:linear-gradient(135deg,#ff5a8a,#b66dff);-webkit-background-clip:text;background-clip:text;color:transparent;}
+.login-page .slogan{font-size:13px;color:#999;text-align:center;margin-top:6px;}
+.login-page .form{margin-top:32px;}
+.login-page .input-row{background:#fff;border-radius:10px;padding:12px 14px;margin-bottom:10px;display:flex;align-items:center;gap:8px;}
+.login-page .input-row .pf{color:#ff5a8a;font-weight:600;font-size:13px;}
+.login-page .input-row .mi{flex:1;font-size:14px;color:#bbb;}
+.login-page .input-row .sc{color:#ff5a8a;font-weight:600;font-size:12px;}
+.login-page .agree{display:flex;align-items:flex-start;gap:5px;font-size:10px;color:#999;margin-top:12px;}
+.login-page .agree .cb{width:14px;height:14px;border-radius:50%;border:1.5px solid #ccc;flex-shrink:0;margin-top:1px;}
+.login-page .agree .cb.on{background:#ff5a8a;border-color:#ff5a8a;display:flex;align-items:center;justify-content:center;color:#fff;font-size:9px;}
+.login-page .agree a{color:#ff5a8a;}
+.login-page .third{margin-top:28px;text-align:center;}
+.login-page .third .label{font-size:10px;color:#bbb;margin-bottom:16px;}
+.login-page .third .ico-row{display:flex;justify-content:center;gap:20px;}
+.login-page .third .ico{width:38px;height:38px;border-radius:50%;background:#fff;display:flex;align-items:center;justify-content:center;font-size:20px;box-shadow:0 3px 8px rgba(0,0,0,.04);}
+
+/* ② 发现页 */
+.page-top{padding:4px 16px 10px;background:#fff;}
+.page-top h1{font-size:22px;font-weight:800;}
+.discover-tabs{display:flex;gap:14px;padding:0 16px 10px;background:#fff;}
+.discover-tabs .tab{font-size:14px;color:#999;font-weight:500;white-space:nowrap;padding:4px 2px;position:relative;}
+.discover-tabs .tab.active{color:#2d2d3a;font-weight:700;font-size:15px;}
+.discover-tabs .tab.active::after{content:"";position:absolute;bottom:-2px;left:50%;transform:translateX(-50%);width:14px;height:2px;border-radius:1px;background:linear-gradient(90deg,#ff5a8a,#b66dff);}
+.filter-bar{display:flex;gap:6px;padding:8px 16px;background:#fff;}
+.filter-bar .chip{padding:5px 10px;background:#f7f7fa;color:#666;font-size:11px;border-radius:12px;white-space:nowrap;}
+.filter-bar .chip.active{background:#fef0f5;color:#ff5a8a;font-weight:600;}
+.user-grid{padding:10px;display:grid;grid-template-columns:1fr 1fr;gap:10px;}
+.user-card{background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 4px 12px rgba(0,0,0,.04);}
+.user-card .cover{width:100%;aspect-ratio:1/1.15;display:flex;align-items:flex-end;padding:6px;position:relative;color:#fff;}
+.user-card .cover-inner{position:relative;z-index:1;width:100%;}
+.user-card .top-flags{position:absolute;top:6px;left:6px;display:flex;gap:3px;z-index:2;}
+.user-card .flag{padding:2px 5px;font-size:9px;background:rgba(0,0,0,.4);color:#fff;border-radius:6px;}
+.user-card .flag.online{background:#4ade80;}
+.user-card .flag.vip-g{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;font-weight:700;}
+.user-card .info{padding:7px 8px;}
+.user-card .info .name{font-size:13px;font-weight:700;display:flex;align-items:center;gap:3px;}
+.user-card .info .meta{font-size:10px;color:#999;margin-top:1px;}
+.user-card .info .tags{display:flex;gap:3px;margin-top:4px;flex-wrap:wrap;}
+
+/* ③ 消息 */
+.msg-quick{padding:12px 16px;background:#fff;display:grid;grid-template-columns:repeat(4,1fr);gap:6px;}
+.msg-quick .qi{display:flex;flex-direction:column;align-items:center;gap:4px;position:relative;}
+.msg-quick .qi .ico{width:38px;height:38px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:16px;color:#fff;}
+.msg-quick .qi .c1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
+.msg-quick .qi .c2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
+.msg-quick .qi .c3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
+.msg-quick .qi .c4{background:linear-gradient(135deg,#4ade80,#22c55e);}
+.msg-quick .qi .lbl{font-size:10px;color:#666;}
+.msg-quick .qi .bd{position:absolute;top:-3px;right:12px;}
+.chat-item{display:flex;align-items:center;padding:10px 16px;gap:10px;border-bottom:1px solid #f5f5f8;background:#fff;}
+.chat-item .av-wrap{position:relative;}
+.chat-item .av-wrap .online-dot{position:absolute;bottom:0;right:0;width:8px;height:8px;background:#4ade80;border:2px solid #fff;border-radius:50%;}
+.chat-item .ci-info{flex:1;min-width:0;}
+.chat-item .ci-info .row1{display:flex;justify-content:space-between;align-items:center;}
+.chat-item .ci-info .name{font-size:14px;font-weight:600;}
+.chat-item .ci-info .time{font-size:10px;color:#bbb;}
+.chat-item .ci-info .last{font-size:12px;color:#999;margin-top:2px;}
+
+/* ④ 个人中心 */
+.me-header{padding:16px;background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;position:relative;}
+.me-header .top-row{display:flex;align-items:center;gap:12px;}
+.me-header .av{width:58px;height:58px;font-size:22px;border:2px solid rgba(255,255,255,.3);}
+.me-header .ns{flex:1;}
+.me-header .name{font-size:18px;font-weight:800;}
+.me-header .id{font-size:10px;opacity:.8;margin-top:1px;}
+.me-header .sign{font-size:11px;margin-top:4px;opacity:.9;}
+.me-header .edit{position:absolute;top:16px;right:16px;padding:4px 10px;background:rgba(255,255,255,.2);border-radius:12px;font-size:10px;}
+.me-stats{display:grid;grid-template-columns:repeat(4,1fr);margin-top:14px;text-align:center;}
+.me-stats .num{font-size:16px;font-weight:800;}
+.me-stats .lbl{font-size:10px;opacity:.8;margin-top:1px;}
+.vip-banner{margin:12px;padding:12px;border-radius:12px;background:linear-gradient(135deg,#3a2a52,#1a0d2e);color:#ffd75e;display:flex;align-items:center;gap:10px;overflow:hidden;position:relative;}
+.vip-banner .vip-i{font-size:24px;}
+.vip-banner .vt .t1{font-size:13px;font-weight:700;}
+.vip-banner .vt .t2{font-size:10px;opacity:.8;margin-top:1px;}
+.vip-banner .vb{padding:5px 12px;background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;border-radius:12px;font-size:11px;font-weight:700;}
+.menu-group{margin:0 12px 12px;background:#fff;border-radius:12px;overflow:hidden;}
+.menu-item{display:flex;align-items:center;padding:12px;gap:10px;border-bottom:1px solid #f5f5f8;}
+.menu-item:last-child{border-bottom:none;}
+.menu-item .mi-ico{width:28px;height:28px;border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:15px;color:#fff;background:linear-gradient(135deg,#ff5a8a,#b66dff);}
+.menu-item .lbl{flex:1;font-size:13px;}
+.menu-item .rt{font-size:11px;color:#999;}
+.menu-item .arr{color:#ccc;font-size:16px;}
+
+/* ⑤ 个人主页 */
+.profile-cover{height:240px;position:relative;color:#fff;flex-shrink:0;}
+.profile-cover::after{content:"";position:absolute;bottom:0;left:0;right:0;height:80px;background:linear-gradient(180deg,transparent,rgba(0,0,0,.5));}
+.profile-cover .top{position:absolute;top:40px;left:0;right:0;padding:0 14px;display:flex;justify-content:space-between;align-items:center;z-index:2;}
+.profile-cover .ic-btn{width:30px;height:30px;border-radius:50%;background:rgba(0,0,0,.3);display:flex;align-items:center;justify-content:center;color:#fff;font-size:16px;}
+.profile-cover .info{position:absolute;bottom:12px;left:16px;right:16px;z-index:2;}
+.profile-cover .name{font-size:22px;font-weight:800;}
+.profile-cover .meta{font-size:11px;margin-top:2px;opacity:.9;}
+.profile-cover .sign{font-size:12px;margin-top:6px;opacity:.95;}
+.profile-section{background:#fff;margin:8px 12px;padding:12px;border-radius:12px;}
+.profile-section h3{font-size:13px;font-weight:700;margin-bottom:10px;}
+.info-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;}
+.info-grid .it .k{font-size:10px;color:#999;}
+.info-grid .it .v{font-size:12px;font-weight:500;}
+.interest-tags{display:flex;flex-wrap:wrap;gap:6px;}
+.album-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px;}
+.album-grid .photo{aspect-ratio:1;border-radius:6px;}
+.photo.p1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
+.photo.p2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
+.photo.p3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
+.photo.p4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
+.photo.p5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
+.photo.p6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
+.profile-cta{display:flex;gap:6px;padding:10px 12px;background:#fff;}
+.profile-cta .b{flex:1;height:40px;border-radius:20px;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;gap:3px;}
+.profile-cta .b.b-gift{background:linear-gradient(135deg,#ffd75e,#ff9a3c);color:#5a3a00;}
+.profile-cta .b.b-fav{background:#fef0f5;color:#ff5a8a;}
+.profile-cta .b.b-chat{background:linear-gradient(135deg,#ff5a8a,#b66dff);color:#fff;box-shadow:0 4px 14px rgba(255,90,138,.3);flex:2;}
+
+/* ⑥ 充值 */
+.recharge-bg{background:linear-gradient(180deg,#1a0d2e,#2a1a3d);color:#fff;height:100%;overflow-y:auto;}
+.recharge-bal{padding:20px 16px;text-align:center;}
+.recharge-bal .lbl{font-size:11px;opacity:.7;}
+.recharge-bal .num{font-size:32px;font-weight:800;color:#ffd75e;margin-top:4px;}
