 <body>
 <div id="app"></div>
 <script src="https://unpkg.com/vue@3.4.27/dist/vue.global.prod.js"></script>
 <script src="api.js"></script>
 <script>
 const { createApp, reactive, ref, computed, watch, onMounted, nextTick } = Vue

 /* ===================== 后端API开关 =====================
  * true  => 假用户管理、批量生成、推送等优先走后端API
  * false => 仅本地 localStorage Mock
  * 调用失败时降级到本地，保证后台仍可用。
  */
 const USE_BACKEND = true
 const API = (typeof window !== 'undefined' && window.starluckApi) ? window.starluckApi : null
 const apiOn = ()=> USE_BACKEND && API

 /* ===================== 共享 Store（与 app.html 同源 localStorage） ===================== */
 const DEFAULT_STORE = {
   loggedIn:false, onboarded:false,
   fakeUsers:[],
   pushRules:{enabled:true, timeSlots:[
     {start:'09:00',end:'11:00',maxPer:1},
     {start:'12:00',end:'14:00',maxPer:1},
     {start:'19:00',end:'22:30',maxPer:2},
   ], strategy:'active', cooldownMin:30},
   pushLog:[],
   csConfig:{aiKey:'', systemPrompt:'你是一个温柔、有趣、积极的年轻女性，正在和一位男性聊天交友。回复要：1) 简短自然（30字内）2) 偶尔反问引导对方说更多 3) 不主动提钱、礼物、转账 4) 不暴露你是AI。', templates:['哈哈是的呢～','你说的对','在做什么呢？','想见你了','晚点聊好吗？','谢谢你的礼物～'], autoReplyEnabled:false},
   adminAnalytics:{pushed:0,opened:0,replied:0,paidAfter:0},
   user:{id:'me',name:'我',av:1,city:'上海',vip:false,vipExpire:'',followers:128,fans:256,friends:42,likes:1280},
   diamonds:666, cash:88.50, isAuthed:false, chatFreeRemain:5,
   chats:[], transactions:[],
   invitedCount:12, invitedPaid:5, invitedReward:686.50, myRank:28, inviteCode:'YQ8888',
   settings:{invisible:false,hideLoc:false,vipOnly:true,sound:true,vibrate:true},
   firstRechargeShown:false,
 }

 const store = reactive(JSON.parse(JSON.stringify(DEFAULT_STORE)))
 try{
   const saved = JSON.parse(localStorage.getItem('yqyr_store')||'null')
   if(saved){
     // 兼容旧版数据：缺字段补默认
     for(const k of Object.keys(DEFAULT_STORE)){
       if(saved[k] === undefined) saved[k] = DEFAULT_STORE[k]
     }
     Object.assign(store, saved)
   }
 }catch(e){ console.warn('load store err', e) }

 let _saveT
 watch(store, ()=>{
   clearTimeout(_saveT)
   _saveT = setTimeout(()=>{
     try{ localStorage.setItem('yqyr_store', JSON.stringify(store)) }catch(e){}
   }, 150)
 }, {deep:true})

 window.addEventListener('storage', e=>{
   if(e.key !== 'yqyr_store' || !e.newValue) return
   try{
     const incoming = JSON.parse(e.newValue)
     for(const k of Object.keys(incoming)){
       if(typeof incoming[k]==='object' && incoming[k]!==null && !Array.isArray(incoming[k])){
         Object.assign(store[k], incoming[k])
       }else{
         store[k] = incoming[k]
       }
     }
   }catch(_){}
 })

 /* ===================== Toast ===================== */
 const toastState = ref('')
 let toastTimer
 const toast = (msg)=>{
   toastState.value = msg
   clearTimeout(toastTimer)
   toastTimer = setTimeout(()=>{ toastState.value = '' }, 2000)
 }

 /* ===================== 智谱 GLM-4-Flash 客户端 ===================== */
 const glm = {
   async chat(messages, opts={}){
     const key = opts.key || store.csConfig.aiKey
     if(!key) throw new Error('未配置 API Key')
     const res = await fetch('https://open.bigmodel.cn/api/paas/v4/chat/completions', {
       method:'POST',
       headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},
       body: JSON.stringify({
         model: opts.model||'glm-4-flash',
         messages,
         temperature: opts.temperature ?? 0.85,
         max_tokens: opts.max_tokens || 200,
       })
     })
     if(!res.ok){
       const err = await res.text().catch(()=>'')
       throw new Error('GLM '+res.status+': '+err.slice(0,140))
     }
     const data = await res.json()
     return data?.choices?.[0]?.message?.content?.trim()||''
   }
 }

 /* ===================== 假用户工具 ===================== */
 const FAKE_NAME_POOL = ['小诗','糖糖','梨花','若兮','茉莉','柚柚','安琪','可可','小鹿','月亮','晓雯','子萱','婉清','雨晴','南风','沐妍','栀子','清欢','一一','阿月']
 const CITY_POOL = ['上海','北京','深圳','广州','杭州','成都','南京','武汉','重庆','西安']
 const SIGN_POOL = ['寻找一个温暖的人','生活不止眼前的苟且','喜欢摄影、咖啡和旅行','期待一场认真的恋爱','喜欢看星星和电影','愿和你共度春秋','一个人也要好好生活','努力做有趣的女生']
 const TAG_POOL = ['旅行','咖啡','摄影','美食','音乐','电影','健身','读书','宠物','瑜伽','汉服','烹饪','逛街','插画','烘焙']

 const randomFakeUser = ()=>{
   const id = 'f'+Date.now()+Math.floor(Math.random()*1000)
   const name = FAKE_NAME_POOL[Math.floor(Math.random()*FAKE_NAME_POOL.length)]
   const tags = []
   while(tags.length<3){
     const t = TAG_POOL[Math.floor(Math.random()*TAG_POOL.length)]
     if(!tags.includes(t)) tags.push(t)
   }
   return {
     id, name, av:Math.floor(Math.random()*8)+1,
     age:20+Math.floor(Math.random()*10),
     city:CITY_POOL[Math.floor(Math.random()*CITY_POOL.length)],
     dist:(0.5+Math.random()*5).toFixed(1)+'km',
     tags,
     sign:SIGN_POOL[Math.floor(Math.random()*SIGN_POOL.length)],
     online:Math.random()>0.3, vip:Math.random()>0.6,
     height:158+Math.floor(Math.random()*15), weight:42+Math.floor(Math.random()*15),
     job:'设计师', edu:'本科', home:'广东深圳', love:'单身',
     persona:'温柔、爱笑、喜欢分享日常',
     csOwner:'', // 客服认领人
     createdAt:Date.now(),
   }
 }

 const findUser = id => {
   if(id == null) return null
   // 兼容字符串/数字 id（后端返回数字、前端旧mock可能是字符串）
   return store.fakeUsers.find(u => u.id === id || String(u.id) === String(id)) || null
 }

 /* ===================== 视图状态 ===================== */
 const view = ref('dashboard')
 const ui = reactive({
   showFakeModal:false, editingFake:null,
   showBatchModal:false, batchCount:5,
   activeConvId:'',
   aiSuggest:'', aiLoading:false,
   reply:'',
 })

 /* ===================== 计算属性 ===================== */
 // 与假用户的对话（运营关心的）
 const fakeConvs = computed(()=>{
   return store.chats.filter(c=>store.fakeUsers.find(f=>f.id===c.uid || String(f.id)===String(c.uid)))
 })
 const totalUnread = computed(()=>fakeConvs.value.reduce((s,c)=>s+(c.unread||0),0))

 const activeConv = computed(()=>store.chats.find(c=>c.id===ui.activeConvId))
 const activeFake = computed(()=>activeConv.value ? findUser(activeConv.value.uid) : null)

 /* ===================== 业务方法 ===================== */
 const ops = {
   addFake(data){
     const fake = data.id ? data : {...randomFakeUser(), ...data}
     if(data.id){
       const i = store.fakeUsers.findIndex(f=>f.id===data.id)
       if(i>=0) store.fakeUsers[i] = fake
     }else{
       store.fakeUsers.push(fake)
     }
     // 同步到后端
     if(apiOn()){
       const payload = {
         id: typeof fake.id === 'number' ? fake.id : undefined,
         name: fake.name, avatarNo: fake.av, age: fake.age, city: fake.city,
         sign: fake.sign, online: !!fake.online, vip: !!fake.vip,
         height: fake.height, weight: fake.weight, job: fake.job, edu: fake.edu,
         hometown: fake.home, loveStatus: fake.love, persona: fake.persona,
         tags: fake.tags ? JSON.stringify(fake.tags) : null, status: 1
       }
       API.admin.saveFakeUser(payload).catch(err=>{
         console.warn('[api] saveFakeUser failed:', err.message)
       })
     }
   },
   delFake(id){
     if(!confirm('确认删除此假用户？相关会话将保留但不再被推送命中')) return
     store.fakeUsers = store.fakeUsers.filter(f=>f.id!==id)
     toast('已删除')
     if(apiOn() && typeof id === 'number'){
       API.admin.deleteFakeUser(id).catch(err=>{
         console.warn('[api] deleteFakeUser failed:', err.message)
       })
     }
   },
   batchGen(n){
     // 优先走后端：可生成持久化记录
     if(apiOn()){
       API.admin.batchGenerate(n).then(list=>{
         // 将后端返回的假用户合并到本地store
         if(Array.isArray(list)){
           list.forEach(f=>{
             store.fakeUsers.push({
               id: f.id, name: f.name, av: f.avatarNo || 1,
               age: f.age, city: f.city, dist: f.dist,
               tags: (typeof f.tags === 'string' ? safeParseJson(f.tags) : f.tags) || [],
               sign: f.sign, online: !!f.online, vip: !!f.vip,
               height: f.height, weight: f.weight, job: f.job, edu: f.edu,
               home: f.hometown, love: f.loveStatus, persona: f.persona,
               csOwner: f.csOwner || '', createdAt: Date.now()
             })
           })
           toast('后端已生成 '+list.length+' 个假用户')
         }
       }).catch(err=>{
         console.warn('[api] batchGenerate failed, fallback local:', err.message)
         for(let i=0;i<n;i++) store.fakeUsers.push(randomFakeUser())
         toast('本地生成 '+n+' 个假用户（后端失败）')
       })
     }else{
       for(let i=0;i<n;i++) store.fakeUsers.push(randomFakeUser())
       toast('已生成 '+n+' 个假用户')
     }
   },
   sendReply(text){
     if(!activeConv.value || !text.trim()) return
     activeConv.value.msgs.push({type:'in', text:text.trim(), time:'刚刚', cs:true})
     activeConv.value.lastMsg = text.trim()
     activeConv.value.time = '刚刚'
     activeConv.value.unread = (activeConv.value.unread||0) + 1
     store.adminAnalytics.replied = (store.adminAnalytics.replied||0) + 1
     // 客服回复同步到后端（站在女用户视角发送消息）
     if(apiOn() && activeConv.value.sessionId){
       API.chat.sendMessage(activeConv.value.sessionId, text.trim()).catch(err=>{
         console.warn('[api] cs sendMessage failed:', err.message)
       })
     }
     ui.reply = ''
     ui.aiSuggest = ''
     toast('已发送')
   },
   async askAI(){
     if(!activeConv.value) return
     if(!store.csConfig.aiKey){ toast('请先在 AI 设置 中配置 API Key'); return }
     ui.aiLoading = true
     ui.aiSuggest = ''
     try{
       const last6 = activeConv.value.msgs.slice(-6).filter(m=>m.type==='in'||m.type==='out')
       const dialog = last6.map(m=>({
         // 站在假女用户的视角：男用户(out)是 user 角色，假女(in/cs)是 assistant 角色
         role: m.type==='out' ? 'user' : 'assistant',
         content: m.text
       }))
       const fk = activeFake.value
       const sys = store.csConfig.systemPrompt + `\n你的角色资料：昵称${fk.name}，${fk.age}岁，${fk.city}，性格：${fk.persona||'温柔'}。`
       const out = await glm.chat([
         {role:'system', content:sys},
         ...dialog,
         ...(dialog.length===0 ? [{role:'user', content:'(对方刚刚向你打招呼，请友好回复)'}] : [])
       ])
       ui.aiSuggest = out
     }catch(e){ toast('AI出错: '+e.message) }
     ui.aiLoading = false
   },
   manualPush(fakeId){
     if(!store.loggedIn){ toast('男用户端未登录，无法推送'); return }
     const fu = store.fakeUsers.find(f=>f.id===fakeId)
     if(!fu){ toast('假用户不存在'); return }
     const greetings = ['你好呀～看你头像感觉好亲切','嗨～在干嘛呢','在吗？刚刷到你～','哈喽～感觉我们好像挺投缘的','突然好想找人聊聊天']
     const greet = greetings[Math.floor(Math.random()*greetings.length)]
     let chat = store.chats.find(c=>c.uid===fu.id)
     if(!chat){
       chat = {id:'c'+Date.now(), uid:fu.id, lastMsg:'', time:'刚刚', unread:0, msgs:[
         {type:'sys', text:'TA向你发起了打招呼'}
       ]}
       store.chats.unshift(chat)
     }
     chat.msgs.push({type:'in', text:greet, time:'刚刚'})
     chat.lastMsg = greet
     chat.time = '刚刚'
     chat.unread = (chat.unread||0) + 1
     store.pushLog.push({ts:Date.now(), fakeUid:fu.id, toUid:store.user.id, slot:'manual', opened:false, replied:false})
     store.adminAnalytics.pushed = (store.adminAnalytics.pushed||0) + 1
     toast('已手动推送：'+fu.name+' → 男用户')

     // 同步到后端（需要 fakeId 和 targetUserId 都是后端数字ID）
     if(apiOn() && typeof fu.id === 'number' && typeof store.user.id === 'number'){
       API.admin.manualPush(fu.id, store.user.id).catch(err=>{
         console.warn('[api] manualPush failed:', err.message)
       })
     }
   },
   // 从后端拉取假用户列表覆盖本地
   syncFakesFromBackend(){
     if(!apiOn()) return Promise.resolve()
     return API.admin.getFakeUsers().then(list=>{
       if(!Array.isArray(list)) return
       store.fakeUsers = list.map(f=>({
         id: f.id, name: f.name, av: f.avatarNo || 1,
         age: f.age, city: f.city, dist: f.dist,
         tags: (typeof f.tags === 'string' ? safeParseJson(f.tags) : f.tags) || [],
         sign: f.sign, online: !!f.online, vip: !!f.vip,
         height: f.height, weight: f.weight, job: f.job, edu: f.edu,
         home: f.hometown, love: f.loveStatus, persona: f.persona,
         csOwner: f.csOwner || '', createdAt: f.createdAt ? new Date(f.createdAt).getTime() : Date.now()
       }))
       toast('已从后端同步 '+list.length+' 个假用户')
     }).catch(err=>{
       console.warn('[api] syncFakes failed:', err.message)
     })
   },
   resetAll(){
     if(!confirm('确认重置所有数据？localStorage 会被清空')) return
     localStorage.removeItem('yqyr_store')
     if(apiOn()) API.auth.logout()
     location.reload()
   }
 }

 // JSON 解析工具
 function safeParseJson(str){
   try { return JSON.parse(str) } catch(e){ return null }
 }

