  * @ai-assisted ai辅助生成,开发人员已完成审查与测试。
  */
 (function (global) {
   'use strict'

   // ============ 基础配置 ============
-  // 默认指向本地后端的 8090 端口（开发环境）
-  // 如需自定义可在引入 api.js 前设置 window.__STARLUCK_API_BASE__
-  var DEFAULT_BASE = 'http://localhost:8090'
+  // 生产环境后端地址
