   let u = MOCK_USERS.find(u=>eq(u.id, id))
   if(u) return u
   // 查 store.fakeUsers（store 可能在脚本前期尚未初始化，用 try 兜底）
   let storeRef = null
   try { storeRef = store } catch(e) {}
   if(storeRef && Array.isArray(storeRef.fakeUsers)){
     const f = storeRef.fakeUsers.find(f=>eq(f.id, id))
     if(f){
       // 把假用户转换成 MOCK_USERS 形状并缓存进 MOCK_USERS，避免重复查询
       const conv = {
         id: f.id,
         name: f.name || '神秘嘉宾',
         av: f.av || f.avatarNo || 1,
         age: f.age || 22,
         city: f.city || '',
         dist: f.dist || '',
         tags: Array.isArray(f.tags) ? f.tags : [],
         sign: f.sign || '',
         online: !!f.online,
         vip: !!f.vip,
         height: f.height || 165,
         weight: f.weight || 50,
         job: f.job || '',
         edu: f.edu || '',
         home: f.home || f.hometown || '',
         love: f.love || f.loveStatus || '单身'
       }
       MOCK_USERS.push(conv)
       return conv
     }
   }
   return MOCK_USERS[0]
 }

