 const PageLogin = {
   components:{StatusBar},
   setup(){
     const phone = ref('')
     const code = ref('')
     const agreed = ref(true)
     const cd = ref(0)
     const loading = ref(false)
     const sendCode = ()=>{
       if(!/^1\d{10}$/.test(phone.value)){ toast('请输入正确手机号'); return }
       cd.value = 60
       const t = setInterval(()=>{ cd.value--; if(cd.value<=0) clearInterval(t) },1000)
       // 调后端，失败回落本地提示
       if(apiOn()){
         biz.sendCode(phone.value)
       }else{
         toast('验证码已发送（演示：123456）')
       }
     }
     const doLogin = ()=>{
       if(!agreed.value){ toast('请同意用户协议'); return }
       if(!/^1\d{10}$/.test(phone.value)){ toast('请输入正确手机号'); return }
       if(!code.value){ toast('请输入验证码'); return }

       const afterLogin = ()=>{
         if(!store.onboarded) go('/onboard')
         else go('/discover')
       }

       if(apiOn()){
         loading.value = true
         biz.loginByApi(phone.value, code.value).then(()=>{
           loading.value = false
           afterLogin()
         }).catch(err=>{
           loading.value = false
           // 后端失败 => 回落本地登录
           console.warn('[api] login failed, fallback local:', err.message)
           toast('后端登录失败：'+err.message+'，已使用本地模式')
           biz.login()
           afterLogin()
         })
       }else{
         biz.login()
         afterLogin()
       }
     }
     return {phone,code,agreed,cd,loading,sendCode,doLogin}
   },
   template:`<div class="screen">
     <status-bar />
     <div class="login-page">
-      <div class="logo">💕</div>
