 const PageOnboard = {
   components:{StatusBar,NavBar},
   setup(){
     const step = ref(1)
     const data = reactive({av:1, gender:'', name:'', birth:'', city:'', height:'', job:'', interests:[]})
     const INTERESTS = ['旅行','咖啡','摄影','美食','音乐','电影','健身','读书','宠物','游戏','汉服','瑜伽']
     const toggleInt = (i)=>{
       const idx = data.interests.indexOf(i)
       if(idx>-1) data.interests.splice(idx,1)
       else if(data.interests.length<8) data.interests.push(i)
     }
     const next = ()=>{
       if(step.value===1 && !data.av){ toast('请上传头像'); return }
       if(step.value===2 && !data.gender){ toast('请选择性别'); return }
       if(step.value===3 && (!data.name||!data.city)){ toast('请填写昵称和城市'); return }
       if(step.value===5 && data.interests.length<3){ toast('至少选3个兴趣'); return }
       if(step.value<5){ step.value++; return }
       biz.finishOnboard({name:data.name||'我', av:data.av, city:data.city||'上海'})
       go('/discover')
     }
     const skip = ()=>{
       biz.finishOnboard({name:'新用户', av:1, city:'上海'})
       go('/discover')
