         chat = {id:'c'+Date.now(), uid:user.value.id, lastMsg:'', time:'刚刚', unread:0, msgs:[
           {type:'sys', text:'你和 '+user.value.name+' 已建立联系，发起友善聊天吧'},
         ]}
         store.chats.unshift(chat)
       }
       go('/chat/'+chat.id)
     }
     const showGift = ()=>{
       let chat = store.chats.find(c=>c.uid===user.value.id)
       if(!chat){
         chat = {id:'c'+Date.now(), uid:user.value.id, lastMsg:'', time:'刚刚', unread:0, msgs:[]}
         store.chats.unshift(chat)
       }
       go('/chat/'+chat.id)
       setTimeout(()=>{ uiState.giftPanel = true }, 200)
     }
