       <div class="br" @click="goToRecharge">充值 ›</div>
     </div>
     <div class="msg-flow">
       <template v-for="(m,i) in chat.msgs" :key="i">
         <div v-if="m.type==='sys'" class="sys-tip">{{m.text}}</div>
         <div v-else-if="m.type==='in'" class="bubble-row">
