 /* ⑯ 视频通话 */
 const PageCall = {
   components:{StatusBar},
   setup(){
     const route = computed(()=>parseRoute(currentRoute.value))
     const user = computed(()=>findUser(route.value.param))
     const sec = ref(0)
     const min = computed(()=>Math.floor(sec.value/60))
     const remainMin = computed(()=>Math.floor(store.diamonds / (store.user.vip?5:6)))
     let timer
     const fmt = (s)=>{
       const m = Math.floor(s/60), ss = s%60
       return String(m).padStart(2,'0')+':'+String(ss).padStart(2,'0')
     }
     const rate = computed(()=>store.user.vip?5:6)
     onMounted(()=>{
       timer = setInterval(()=>{
         sec.value++
         if(sec.value%60===0){
           const r = biz.callMinute(user.value.id)
           if(!r){ toast('钻石不足，通话结束'); hangup() }
         }
       },1000)
     })
     const hangup = ()=>{
       clearInterval(timer)
       toast('通话结束，时长 '+fmt(sec.value))
       back()
     }
     return {user,sec,min,fmt,rate,remainMin,store,hangup,go}
   },
   template:`<div class="screen">
     <div class="call-page">
       <div class="call-bg" :class="'av-'+user.av">{{user.name[0]}}</div>
       <div class="call-self">我</div>
       <div class="call-top">
         <div class="ct-l">
           <div class="nm">{{user.name}}</div>
           <div class="tm">● {{fmt(sec)}}</div>
         </div>
         <div class="ct-r">💎 {{rate}}/分</div>
       </div>
       <div v-if="remainMin<10" class="call-warning">⚠️ 余额仅剩 {{remainMin}} 分钟，请及时充值</div>
       <div class="call-bottom">
         <div class="call-balance">
           <div class="bal">余额 <b>{{store.diamonds}}💎</b> · 已消耗 {{min*rate}}💎</div>
           <div class="recharge" @click="go('/recharge')">充值</div>
         </div>
         <div class="call-controls">
           <div class="cb">🔇</div>
           <div class="cb">🔄</div>
           <div class="cb" @click="toast('调起礼物')">🎁</div>
           <div class="cb">💬</div>
           <div class="cb hangup" @click="hangup">📞</div>
         </div>
       </div>
     </div>
   </div>`
 }

