     chat.lastMsg = greet
     chat.time = '刚刚'
     chat.unread = (chat.unread||0) + 1
     store.pushLog.push({ts:Date.now(), fakeUid:fu.id, toUid:store.user.id, slot:slot.start, opened:false, replied:false})
     store.adminAnalytics.pushed = (store.adminAnalytics.pushed||0) + 1
     // 全局 fakeUsers 池没有真实头像，注入到 MOCK_USERS 以便其它页面渲染
