     @Override
     public void updateProfile(Long userId, UserProfile profile) {
         UserProfile existing = userProfileMapper.selectOne(
                 new LambdaQueryWrapper<UserProfile>().eq(UserProfile::getUserId, userId));
         if (existing == null) {
