+        <span v-if="testOut" style="font-size:12px;color:#666;flex:1;">{{testOut}}</span>
+      </div>
+      <div style="margin-top:12px;font-size:11px;color:#888;background:#fef3c7;padding:10px;border-radius:6px;">
+        ⚠️ 注意：当前架构为纯前端调用，API Key 会进入前端 localStorage 与浏览器请求头。<strong>仅适合内部演示</strong>。正式上线必须改为后端代理，避免 Key 泄露。
+      </div>
+    </div>
+
+    <div class="card" style="margin-bottom:14px;">
+      <div class="card-title"><span>System Prompt（女性角色设定）</span></div>
+      <textarea class="input" v-model="store.csConfig.systemPrompt" rows="6"></textarea>
+      <div style="margin-top:8px;font-size:11px;color:#888;">客服端调 AI 时，会以本 prompt + 假用户具体资料 + 最近 6 轮对话 作为上下文，让 AI 扮演该假女用户回复。</div>
+    </div>
+
+    <div class="card" style="margin-bottom:14px;">
+      <div class="card-title">
+        <span>快捷话术模板</span>
+        <button class="btn small ghost" @click="addTpl">➕ 添加</button>
+      </div>
+      <div style="display:flex;flex-wrap:wrap;gap:6px;">
+        <span v-for="(t,i) in store.csConfig.templates" :key="i" class="tag" style="padding:6px 10px;font-size:12px;background:#fafafd;">
+          {{t}} <span @click="delTpl(i)" style="margin-left:6px;color:#ff5c8a;cursor:pointer;">×</span>
+        </span>
+      </div>
+    </div>
+
+    <div class="card">
+      <div class="card-title"><span>关于"AI 给男用户提示"</span></div>
+      <div style="font-size:12px;color:#666;line-height:1.7;">
+        男用户端 app.html 的 PageChat 已加入"💡 AI 建议"按钮：用户在和任何对象（包括真假用户）聊天时，点击该按钮，AI 会以"恋爱沟通教练"视角根据最近 6 轮对话，给出一条 30 字内回复建议。<br>
+        男用户端 AI 调用使用同一份 csConfig.aiKey（按需可拆分）。
+      </div>
+    </div>
+  </div>`
+}
+
+/* 推送日志 */
+const ViewLogs = {
+  setup(){
+    const logs = computed(()=>store.pushLog.slice().reverse())
+    const fmt = (ts)=>{
+      const d = new Date(ts)
+      return d.toLocaleDateString()+' '+d.toLocaleTimeString()
+    }
+    const clearLog = ()=>{
+      if(!confirm('清空所有推送日志？')) return
+      store.pushLog = []
+      toast('已清空')
+    }
+    return {store, logs, fmt, clearLog, findUser}
+  },
+  template:`<div>
+    <div class="card">
+      <div class="card-title">
+        <span>推送日志（共 {{logs.length}} 条）</span>
+        <button class="btn small ghost" @click="clearLog" style="color:#ff5c8a;">清空日志</button>
+      </div>
+      <div v-if="!logs.length" class="empty"><div class="ei">📋</div>暂无推送记录</div>
+      <div v-else>
+        <div v-for="(l,i) in logs" :key="i" class="log-row">
+          <span class="t">{{fmt(l.ts)}}</span>
+          <div class="av" :class="'av-'+(findUser(l.fakeUid)?.av||1)">{{findUser(l.fakeUid)?.name?.[0]||'?'}}</div>
+          <div class="a">
+            <b>{{findUser(l.fakeUid)?.name||'(已删除)'}}</b> → 男用户 <b>{{l.toUid}}</b>
+            <span class="tag" style="margin-left:6px;">{{l.slot==='manual'?'手动':'时段 '+l.slot}}</span>
+          </div>
+          <span class="tag" :class="l.replied?'green':l.opened?'gold':''">
+            {{l.replied?'✓ 已回复':l.opened?'已查看':'未查看'}}
+          </span>
+        </div>
+      </div>
+    </div>
+  </div>`
+}
+
+/* 根 App */
+const App = {
+  components:{ViewDashboard,ViewFakes,ViewWorkbench,ViewPush,ViewAI,ViewLogs},
+  setup(){
+    const NAVS = [
+      {k:'dashboard',ic:'📊',n:'数据看板'},
+      {k:'fakes',ic:'👤',n:'假用户管理'},
+      {k:'workbench',ic:'💬',n:'客服工作台'},
+      {k:'push',ic:'📡',n:'推送规则'},
+      {k:'ai',ic:'🤖',n:'AI 设置'},
+      {k:'logs',ic:'📋',n:'推送日志'},
+    ]
+    const titles = {dashboard:'数据看板',fakes:'假用户管理',workbench:'客服工作台',push:'推送规则',ai:'AI 设置',logs:'推送日志'}
+    const currentView = computed(()=>{
+      const map = {dashboard:'view-dashboard',fakes:'view-fakes',workbench:'view-workbench',push:'view-push',ai:'view-ai',logs:'view-logs'}
+      return map[view.value]||'view-dashboard'
+    })
+    const appOnline = computed(()=>store.loggedIn)
+    return {view, NAVS, titles, currentView, store, toastState, totalUnread, appOnline}
+  },
+  template:`<div class="layout">
+    <div class="sidebar">
+      <div class="logo"><span class="ic">💕</span>Starluck 后台</div>
+      <div class="nav">
+        <div v-for="n in NAVS" :key="n.k" class="nav-item" :class="{active:view===n.k}" @click="view=n.k">
+          <span class="ic">{{n.ic}}</span>
+          <span>{{n.n}}</span>
+          <span v-if="n.k==='workbench'&&totalUnread" class="bd">{{totalUnread}}</span>
+        </div>
+      </div>
+      <div class="footer">
+        v1.0 · 演示版本<br>
+        <span style="opacity:.6;">localStorage 共享于 app.html</span>
+      </div>
+    </div>
+    <div class="main">
+      <div class="header">
+        <div class="title">{{titles[view]||''}}</div>
+        <div class="right">
+          <span class="dot" :class="{off:!appOnline}">{{appOnline?'男用户端已登录':'男用户端未登录'}}</span>
+          <span>钻石 💎 {{store.diamonds}}</span>
+          <span>余额 ¥{{store.cash.toFixed(2)}}</span>
+          <a href="app.html" target="_blank" class="btn small ghost" style="text-decoration:none;">↗ 打开 app.html</a>
+        </div>
+      </div>
+      <div class="content">
+        <component :is="currentView" />
+      </div>
+    </div>
+    <div v-if="toastState" class="toast">{{toastState}}</div>
+  </div>`
+}
+
+createApp(App).mount('#app')
+
+// 调试入口
+window.admin = { store, ops, view, ui, glm, toast }
+</script>
+</body>
+</html>

