+<!DOCTYPE html>
+<html lang="zh-CN">
+<head>
+<meta charset="UTF-8" />
+<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,minimum-scale=1.0,user-scalable=no,viewport-fit=cover" />
+<meta name="format-detection" content="telephone=no, email=no, address=no" />
+<meta name="apple-mobile-web-app-capable" content="yes" />
+<meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
+<meta name="x5-orientation" content="portrait" />
+<meta name="screen-orientation" content="portrait" />
+<meta name="full-screen" content="yes" />
+<title>Starluck</title>
+<style>
+*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
+html,body{font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif;background:#06020f;color:#fff;line-height:1.4;font-size:14px;overflow:hidden;}
+body{display:flex;align-items:center;justify-content:center;min-height:100vh;}
+img{max-width:100%;display:block;}
+button{border:none;outline:none;background:none;font-family:inherit;cursor:pointer;}
+input,textarea{border:none;outline:none;font-family:inherit;background:none;color:inherit;}
+input::placeholder,textarea::placeholder{color:rgba(255,255,255,0.35);}
+a{text-decoration:none;color:inherit;}
+
+/* 手机壳（桌面端可见） */
+.phone-shell{width:375px;height:812px;background:#1f0d3a;border-radius:42px;box-shadow:0 30px 80px rgba(0,0,0,.45),0 0 0 14px #111 inset,0 0 0 18px #2a2a2a;position:relative;overflow:hidden;}
+.phone-shell::before{content:"";position:absolute;top:8px;left:50%;transform:translateX(-50%);width:130px;height:28px;background:#111;border-radius:0 0 18px 18px;z-index:9999;}
+
+/* === ✨ Starluck · 全局星光层（叠加在所有页面背景上方） === */
+.screen::before{content:"";position:absolute;inset:0;pointer-events:none;z-index:0;background-image:radial-gradient(1.5px 1.5px at 12% 18%,#fff,transparent),radial-gradient(1px 1px at 28% 42%,#e0c8ff,transparent),radial-gradient(2px 2px at 47% 76%,#fff,transparent),radial-gradient(1px 1px at 63% 23%,#ffd6f5,transparent),radial-gradient(1.5px 1.5px at 78% 57%,#fff,transparent),radial-gradient(1px 1px at 88% 88%,#e0c8ff,transparent),radial-gradient(1px 1px at 92% 14%,#fff,transparent),radial-gradient(1.5px 1.5px at 35% 64%,#ffd6f5,transparent),radial-gradient(1px 1px at 56% 91%,#fff,transparent);background-size:380px 380px;opacity:.6;animation:slTwinkle 6s ease-in-out infinite;}
+.screen > *{position:relative;z-index:1;}
+@keyframes slTwinkle{0%,100%{opacity:.35;}50%{opacity:.7;}}
+@media(prefers-reduced-motion:reduce){.screen::before{animation:none;}}
+
+@media(max-width:430px){
+  body{background:#06020f;}
+  .phone-shell{width:100vw;height:100vh;border-radius:0;box-shadow:none;}
+  .phone-shell::before{display:none;}
+}
+
+/* 屏幕容器 */
+.screen{width:100%;height:100%;background:linear-gradient(180deg,#1f0d3a 0%,#0a0418 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}
+
+/* 状态栏 */
+.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:13px;font-weight:600;color:#fff;flex-shrink:0;position:relative;z-index:10;}
+.status-bar .icons{display:flex;gap:5px;align-items:center;}
+.status-bar.dark{color:#fff;}
+
+/* 顶部导航条 */
+.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:#1f0d3a;flex-shrink:0;position:relative;z-index:9;}
+.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:22px;color:#fff;}
+.nav-bar .title{font-size:17px;font-weight:700;color:#fff;flex:1;text-align:center;}
+.nav-bar .right{min-width:32px;font-size:14px;color:rgba(255,255,255,0.7);text-align:right;}
+.nav-bar.transparent{background:transparent;}
+.nav-bar.dark{background:transparent;}
+.nav-bar.dark .back,.nav-bar.dark .title,.nav-bar.dark .right{color:#fff;}
+
+/* 页面顶部大标题区 */
