+    const sec = ref(0)
+    const min = computed(()=>Math.floor(sec.value/60))
+    const remainMin = computed(()=>Math.floor(store.diamonds / (store.user.vip?5:6)))
+    let timer
+    const fmt = (s)=>{
+      const m = Math.floor(s/60), ss = s%60
+      return String(m).padStart(2,'0')+':'+String(ss).padStart(2,'0')
+    }
+    const rate = computed(()=>store.user.vip?5:6)
+    onMounted(()=>{
+      timer = setInterval(()=>{
+        sec.value++
+        if(sec.value%60===0){
+          const r = biz.callMinute(user.value.id)
+          if(!r){ toast('钻石不足，通话结束'); hangup() }
+        }
+      },1000)
+    })
+    const hangup = ()=>{
+      clearInterval(timer)
+      toast('通话结束，时长 '+fmt(sec.value))
+      back()
+    }
+    return {user,sec,min,fmt,rate,remainMin,store,hangup,go}
