+/* 手机壳 */
+.phone-shell{width:375px;height:812px;background:rgba(180,140,255,0.06);border-radius:42px;box-shadow:0 20px 60px rgba(0,0,0,.2),0 0 0 10px #222 inset,0 0 0 14px #1a1a2e;position:relative;overflow:hidden;}
