+<!DOCTYPE html>
+<html lang="zh-CN">
+<head>
+<meta charset="UTF-8" />
+<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,minimum-scale=1.0,user-scalable=no,viewport-fit=cover" />
+<meta name="format-detection" content="telephone=no, email=no, address=no" />
+<meta name="apple-mobile-web-app-capable" content="yes" />
+<meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
+<meta name="x5-orientation" content="portrait" />
+<meta name="screen-orientation" content="portrait" />
+<meta name="full-screen" content="yes" />
+<title>一青友人</title>
+<style>
+*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
+html,body{font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif;background:#1a1a2e;color:#2d2d3a;line-height:1.4;font-size:14px;overflow:hidden;}
+body{display:flex;align-items:center;justify-content:center;min-height:100vh;}
+img{max-width:100%;display:block;}
+button{border:none;outline:none;background:none;font-family:inherit;cursor:pointer;}
+input,textarea{border:none;outline:none;font-family:inherit;background:none;}
+a{text-decoration:none;color:inherit;}
+
+/* 手机壳（桌面端可见） */
+.phone-shell{width:375px;height:812px;background:#fff;border-radius:42px;box-shadow:0 30px 80px rgba(0,0,0,.45),0 0 0 14px #111 inset,0 0 0 18px #2a2a2a;position:relative;overflow:hidden;}
+.phone-shell::before{content:"";position:absolute;top:8px;left:50%;transform:translateX(-50%);width:130px;height:28px;background:#111;border-radius:0 0 18px 18px;z-index:9999;}
+
+@media(max-width:430px){
+  body{background:#fff;}
+  .phone-shell{width:100vw;height:100vh;border-radius:0;box-shadow:none;}
+  .phone-shell::before{display:none;}
+}
+
+/* 屏幕容器 */
+.screen{width:100%;height:100%;background:linear-gradient(180deg,#fef6f9 0%,#f3eaff 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}
+
+/* 状态栏 */
+.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:13px;font-weight:600;color:#2d2d3a;flex-shrink:0;position:relative;z-index:10;}
+.status-bar .icons{display:flex;gap:5px;align-items:center;}
+.status-bar.dark{color:#fff;}
+
+/* 顶部导航条 */
+.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:#fff;flex-shrink:0;position:relative;z-index:9;}
+.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:22px;color:#2d2d3a;}
+.nav-bar .title{font-size:17px;font-weight:700;color:#2d2d3a;flex:1;text-align:center;}
+.nav-bar .right{min-width:32px;font-size:14px;color:#666;text-align:right;}
+.nav-bar.transparent{background:transparent;}
+.nav-bar.dark{background:transparent;}
+.nav-bar.dark .back,.nav-bar.dark .title,.nav-bar.dark .right{color:#fff;}
+
+/* 页面顶部大标题区 */
+.page-top{padding:6px 18px 14px;background:#fff;flex-shrink:0;}
+.page-top h1{font-size:24px;font-weight:800;color:#2d2d3a;margin-bottom:2px;}
+.page-top .sub{font-size:12px;color:#999;}
+
+/* 主内容区 */
+.content{flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch;}
+.content::-webkit-scrollbar{display:none;}
+
+/* 底部 Tab Bar */
+.tab-bar{height:60px;display:flex;background:#fff;border-top:1px solid #f0f0f5;flex-shrink:0;padding-bottom:env(safe-area-inset-bottom,0);}
+.tab-bar .tab-item{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;color:#999;font-size:11px;gap:2px;}
+.tab-bar .tab-item .ico{font-size:22px;line-height:1;}
+.tab-bar .tab-item.active{color:#ff5a8a;font-weight:600;}
+
+/* 主CTA按钮 */
+.btn{display:inline-flex;align-items:center;justify-content:center;height:46px;padding:0 24px;border-radius:23px;font-size:15px;font-weight:600;background:linear-gradient(135deg,#ff5a8a 0%,#b66dff 100%);color:#fff;box-shadow:0 6px 18px rgba(255,90,138,.35);transition:transform .15s ease;}
+.btn:active{transform:scale(.96);}
+.btn.block{width:100%;}
+.btn.gold{background:linear-gradient(135deg,#ffd75e 0%,#ff9a3c 100%);color:#5a3a00;box-shadow:0 6px 18px rgba(255,154,60,.35);}
+.btn.ghost{background:#fff;color:#ff5a8a;border:1.5px solid #ff5a8a;box-shadow:none;}
+.btn.dark{background:#2d2d3a;box-shadow:0 6px 18px rgba(0,0,0,.2);}
+.btn.small{height:32px;padding:0 14px;border-radius:16px;font-size:13px;}
+.btn.danger{background:linear-gradient(135deg,#ff3b5c 0%,#ff5a8a 100%);}
+.btn:disabled{opacity:.5;box-shadow:none;}
+
+/* 头像渐变 */
+.av{width:50px;height:50px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:18px;}
+.av-1{background:linear-gradient(135deg,#ff5a8a,#b66dff);}
+.av-2{background:linear-gradient(135deg,#7c5aff,#4ade80);}
+.av-3{background:linear-gradient(135deg,#ffd75e,#ff9a3c);}
+.av-4{background:linear-gradient(135deg,#ff3b5c,#ffd75e);}
+.av-5{background:linear-gradient(135deg,#4ade80,#7c5aff);}
+.av-6{background:linear-gradient(135deg,#b66dff,#ff5a8a);}
+.av-7{background:linear-gradient(135deg,#ff9a3c,#ff3b5c);}
+.av-8{background:linear-gradient(135deg,#7c5aff,#ff5a8a);}
+
+/* 通用卡片 */
+.card{background:#fff;border-radius:14px;padding:14px;box-shadow:0 6px 16px rgba(0,0,0,.05);}
+
+/* 标签 */
+.tag{display:inline-flex;align-items:center;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:500;background:#fef0f5;color:#ff5a8a;}
+.tag.purple{background:#f3eaff;color:#7c5aff;}
