+<script>
+/* ========== 搜索过滤 ========== */
+const searchInput = document.getElementById('searchInput')
+const resultCount = document.getElementById('resultCount')
+const btnAll = document.getElementById('btnAll')
+const btnSearch = document.getElementById('btnSearch')
+const sections = document.querySelectorAll('.screen-section')
+const navItems = document.querySelectorAll('.nav-item')
+
+let searchMode = false
+
+function doSearch(){
+  const q = searchInput.value.trim().toLowerCase()
+  let visibleCount = 0
+  sections.forEach(s=>{
+    const kw = (s.dataset.keywords || '').toLowerCase()
+    const text = s.textContent.toLowerCase()
+    const match = !q || kw.includes(q) || text.includes(q)
+    s.classList.toggle('hidden', !match)
+    if(match) visibleCount++
+  })
+  resultCount.textContent = q ? `匹配 ${visibleCount} 屏` : '共 22 屏 · 340+ 元素'
+  btnAll.classList.toggle('active', !q)
+  btnSearch.style.display = q ? '' : 'none'
+  btnSearch.classList.toggle('active', !!q)
+  searchMode = !!q
+  if(!q) highlightClear()
+}
+
+function showAll(){
+  searchInput.value = ''
+  sections.forEach(s=>s.classList.remove('hidden'))
+  resultCount.textContent = '共 22 屏 · 340+ 元素'
+  btnAll.classList.add('active')
+  btnSearch.style.display = 'none'
+  searchMode = false
+  highlightClear()
+}
+
+/* ========== 深色模式 ========== */
+function toggleDark(){
+  document.body.classList.toggle('dark')
+  const btn = document.querySelector('.toolbar .btn-sm:last-child')
+  const isDark = document.body.classList.contains('dark')
+  btn.textContent = isDark ? '☀️ 浅色模式' : '🌙 深色模式'
+}
+
+/* ========== 侧边栏活跃追踪 ========== */
+function updateActiveNav(){
+  let closestId = null
+  let minDist = Infinity
+  navItems.forEach(item=>{
+    const href = item.getAttribute('href')
+    if(!href || !href.startsWith('#s')) return
+    const target = document.querySelector(href)
+    if(!target) return
+    const rect = target.getBoundingClientRect()
+    const dist = Math.abs(rect.top - 200)
+    if(dist < minDist){ minDist = dist; closestId = href }
+  })
+  navItems.forEach(item=>{
+    item.classList.toggle('active', item.getAttribute('href') === closestId)
+  })
+}
+
+window.addEventListener('scroll', updateActiveNav, {passive:true})
