--- themes/warm-night/app.html	
+++ themes/warm-night/app.html	
@@ -0,0 +1,2841 @@
+<!DOCTYPE html>
+<html lang="zh-CN">
+<head>
+<meta charset="UTF-8" />
+<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,minimum-scale=1.0,user-scalable=no,viewport-fit=cover" />
+<meta name="format-detection" content="telephone=no, email=no, address=no" />
+<meta name="apple-mobile-web-app-capable" content="yes" />
+<meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />
+<meta name="x5-orientation" content="portrait" />
+<meta name="screen-orientation" content="portrait" />
+<meta name="full-screen" content="yes" />
+<title>Starluck · 暖夜蓝</title>
+<style>
+*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent;}
+html,body{font-family:-apple-system,BlinkMacSystemFont,"PingFang SC","Microsoft YaHei",sans-serif;background:#050714;color:#fff;line-height:1.4;font-size:14px;overflow:hidden;}
+body{display:flex;align-items:center;justify-content:center;min-height:100vh;}
+img{max-width:100%;display:block;}
+button{border:none;outline:none;background:none;font-family:inherit;cursor:pointer;}
+input,textarea{border:none;outline:none;font-family:inherit;background:none;color:inherit;}
+input::placeholder,textarea::placeholder{color:rgba(255,255,255,0.35);}
+a{text-decoration:none;color:inherit;}
+
+/* 手机壳（桌面端可见） */
+.phone-shell{width:375px;height:812px;background:#23264c;border-radius:42px;box-shadow:0 30px 80px rgba(0,0,0,.45),0 0 0 14px #111 inset,0 0 0 18px #2a2a2a;position:relative;overflow:hidden;}
+.phone-shell::before{content:"";position:absolute;top:8px;left:50%;transform:translateX(-50%);width:130px;height:28px;background:#111;border-radius:0 0 18px 18px;z-index:9999;}
+
+/* === ✨ Starluck · 全局星光层（叠加在所有页面背景上方） === */
+.screen::before{content:"";position:absolute;inset:0;pointer-events:none;z-index:0;background-image:radial-gradient(1.5px 1.5px at 12% 18%,#fff,transparent),radial-gradient(1px 1px at 28% 42%,#e0c8ff,transparent),radial-gradient(2px 2px at 47% 76%,#fff,transparent),radial-gradient(1px 1px at 63% 23%,#ffd6e8,transparent),radial-gradient(1.5px 1.5px at 78% 57%,#fff,transparent),radial-gradient(1px 1px at 88% 88%,#e0c8ff,transparent),radial-gradient(1px 1px at 92% 14%,#fff,transparent),radial-gradient(1.5px 1.5px at 35% 64%,#ffd6e8,transparent),radial-gradient(1px 1px at 56% 91%,#fff,transparent);background-size:380px 380px;opacity:.6;animation:slTwinkle 6s ease-in-out infinite;}
+.screen > *{position:relative;z-index:1;}
+@keyframes slTwinkle{0%,100%{opacity:.35;}50%{opacity:.7;}}
+@media(prefers-reduced-motion:reduce){.screen::before{animation:none;}}
+
+@media(max-width:430px){
+  body{background:#050714;}
+  .phone-shell{width:100vw;height:100vh;border-radius:0;box-shadow:none;}
+  .phone-shell::before{display:none;}
+}
+
+/* 屏幕容器 */
+.screen{width:100%;height:100%;background:linear-gradient(180deg,#23264c 0%,#080a18 100%);position:relative;overflow:hidden;display:flex;flex-direction:column;}
+
+/* 状态栏 */
+.status-bar{height:38px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 24px 6px;font-size:13px;font-weight:600;color:#fff;flex-shrink:0;position:relative;z-index:10;}
+.status-bar .icons{display:flex;gap:5px;align-items:center;}
+.status-bar.dark{color:#fff;}
+
+/* 顶部导航条 */
+.nav-bar{height:48px;display:flex;align-items:center;justify-content:space-between;padding:0 14px;background:#23264c;flex-shrink:0;position:relative;z-index:9;}
+.nav-bar .back{width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:22px;color:#fff;}
+.nav-bar .title{font-size:17px;font-weight:700;color:#fff;flex:1;text-align:center;}
+.nav-bar .right{min-width:32px;font-size:14px;color:rgba(255,255,255,0.7);text-align:right;}
+.nav-bar.transparent{background:transparent;}
+.nav-bar.dark{background:transparent;}
+.nav-bar.dark .back,.nav-bar.dark .title,.nav-bar.dark .right{color:#fff;}
+
+/* 页面顶部大标题区 */
+.page-top{padding:6px 18px 14px;background:#23264c;flex-shrink:0;}
+.page-top h1{font-size:24px;font-weight:800;color:#fff;margin-bottom:2px;}
+.page-top .sub{font-size:12px;color:rgba(255,255,255,0.55);}
+
+/* 主内容区 */
+.content{flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch;}
+.content::-webkit-scrollbar{display:none;}
+
+/* 底部 Tab Bar */
+.tab-bar{height:60px;display:flex;background:#23264c;border-top:1px solid rgba(255,255,255,0.06);flex-shrink:0;padding-bottom:env(safe-area-inset-bottom,0);}
+.tab-bar .tab-item{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;color:rgba(255,255,255,0.55);font-size:11px;gap:2px;}
+.tab-bar .tab-item .ico{font-size:22px;line-height:1;}
+.tab-bar .tab-item.active{color:#ff8ab0;font-weight:600;}
+
+/* 主CTA按钮 */
+.btn{display:inline-flex;align-items:center;justify-content:center;height:46px;padding:0 24px;border-radius:23px;font-size:15px;font-weight:600;background:linear-gradient(135deg,#ff8ab0 0%,#7a9eff 100%);color:#fff;box-shadow:0 6px 18px rgba(255,138,176,.35);transition:transform .15s ease;}
+.btn:active{transform:scale(.96);}
+.btn.block{width:100%;}
+.btn.gold{background:linear-gradient(135deg,#ffd966 0%,#ff9a3c 100%);color:#3a2a00;box-shadow:0 6px 18px rgba(255,154,60,.35);}
+.btn.ghost{background:rgba(255,138,176,0.1);color:#ff8ab0;border:1.5px solid #ff8ab0;box-shadow:none;}
+.btn.dark{background:#2d2d3a;box-shadow:0 6px 18px rgba(0,0,0,.2);}
+.btn.small{height:32px;padding:0 14px;border-radius:16px;font-size:13px;}
+.btn.danger{background:linear-gradient(135deg,#ff5c8a 0%,#ff8ab0 100%);}
+.btn:disabled{opacity:.5;box-shadow:none;}
+
+/* 头像渐变 */
+.av{width:50px;height:50px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;color:#fff;font-weight:700;flex-shrink:0;font-size:18px;}
+.av-1{background:linear-gradient(135deg,#ff8ab0,#7a9eff);}
+.av-2{background:linear-gradient(135deg,#a8c4ff,#5eead4);}
+.av-3{background:linear-gradient(135deg,#ffd966,#ff9a3c);}
+.av-4{background:linear-gradient(135deg,#ff5c8a,#ffd966);}
+.av-5{background:linear-gradient(135deg,#5eead4,#a8c4ff);}
+.av-6{background:linear-gradient(135deg,#7a9eff,#ff8ab0);}
+.av-7{background:linear-gradient(135deg,#ff9a3c,#ff5c8a);}
+.av-8{background:linear-gradient(135deg,#a8c4ff,#ff8ab0);}
+
+/* 通用卡片 */
+.card{background:#23264c;border:1px solid rgba(255,138,176,.18);border-radius:14px;padding:14px;box-shadow:0 6px 20px rgba(8,10,24,.4);}
+
+/* 标签 */
+.tag{display:inline-flex;align-items:center;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:500;background:rgba(255,138,176,0.15);color:#ff8ab0;}
+.tag.purple{background:#080a18;color:#a8c4ff;}
+.tag.gold{background:rgba(255,217,102,0.15);color:#ff9a3c;}
+.tag.green{background:rgba(94,234,212,0.15);color:#5eead4;}
+.tag.gray{background:rgba(255,255,255,0.06);color:rgba(255,255,255,0.7);}
+.tag.vip{background:linear-gradient(135deg,#ffd966,#ff9a3c);color:#3a2a00;font-weight:700;}
+
+/* 红点 */
+.badge{display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 5px;background:#ff5c8a;color:#fff;font-size:10px;font-weight:700;border-radius:9px;}
+.badge.dot{min-width:8px;height:8px;padding:0;border-radius:50%;}
+
+/* === ① 登录页 === */
+.login-page{padding:32px 28px;display:flex;flex-direction:column;height:100%;background:linear-gradient(180deg,#23264c 0%,#080a18 100%);}
+.login-page .logo{font-size:48px;text-align:center;margin-top:60px;}
+.login-page h1{font-size:32px;font-weight:800;text-align:center;margin-top:14px;background:linear-gradient(135deg,#ff8ab0,#7a9eff);-webkit-background-clip:text;background-clip:text;color:transparent;}
+.login-page .slogan{font-size:14px;color:rgba(255,255,255,0.55);text-align:center;margin-top:8px;}
+.login-page .form{margin-top:48px;}
+.login-page .input-row{background:rgba(255,138,176,0.1);border:1px solid rgba(255,138,176,0.25);border-radius:12px;padding:14px 16px;margin-bottom:12px;display:flex;align-items:center;gap:10px;backdrop-filter:blur(8px);}
+.login-page .input-row .prefix{color:#ff8ab0;font-weight:600;}
+.login-page .input-row input{flex:1;font-size:15px;color:#fff;}
+.login-page .input-row input::placeholder{color:rgba(255,255,255,0.4);}
+.login-page .input-row .send-code{color:#7a9eff;font-weight:600;font-size:13px;}
+.login-page .send-code.disabled{color:rgba(255,255,255,0.3);}
+.login-page .agree{display:flex;align-items:flex-start;gap:6px;font-size:11px;color:rgba(255,255,255,0.55);margin-top:14px;}
+.login-page .agree .cb{width:14px;height:14px;border-radius:50%;border:1.5px solid #ccc;flex-shrink:0;margin-top:2px;}
+.login-page .agree .cb.on{background:#ff8ab0;border-color:#ff8ab0;color:#fff;display:flex;align-items:center;justify-content:center;font-size:10px;}
+.login-page .agree a{color:#ff8ab0;}
+.login-page .third{margin-top:40px;text-align:center;}
+.login-page .third .label{font-size:11px;color:rgba(255,255,255,0.4);position:relative;margin-bottom:20px;}
+.login-page .third .label::before,.login-page .third .label::after{content:"";position:absolute;top:50%;width:40px;height:1px;background:#eee;}
+.login-page .third .label::before{right:calc(50% + 50px);}
+.login-page .third .label::after{left:calc(50% + 50px);}
+.login-page .third .ico-row{display:flex;justify-content:center;gap:24px;}
+.login-page .third .ico{width:44px;height:44px;border-radius:50%;background:#23264c;display:flex;align-items:center;justify-content:center;font-size:22px;box-shadow:0 4px 14px rgba(8,10,24,.3);}
+
+/* === ② 发现/用户列表 === */
+.discover-tabs{display:flex;gap:18px;padding:0 18px 12px;background:#23264c;overflow-x:auto;}
+.discover-tabs::-webkit-scrollbar{display:none;}
+.discover-tabs .tab{font-size:15px;color:rgba(255,255,255,0.55);font-weight:500;white-space:nowrap;padding:6px 2px;position:relative;}
+.discover-tabs .tab.active{color:#fff;font-weight:700;font-size:17px;}
+.discover-tabs .tab.active::after{content:"";position:absolute;bottom:-2px;left:50%;transform:translateX(-50%);width:18px;height:3px;border-radius:2px;background:linear-gradient(90deg,#ff8ab0,#7a9eff);}
+.filter-bar{display:flex;gap:8px;padding:10px 18px;background:#23264c;overflow-x:auto;}
+.filter-bar::-webkit-scrollbar{display:none;}
+.filter-bar .chip{padding:6px 12px;background:rgba(255,138,176,0.08);color:rgba(255,255,255,0.7);font-size:12px;border-radius:14px;white-space:nowrap;}
+.filter-bar .chip.active{background:rgba(255,138,176,0.15);color:#ff8ab0;font-weight:600;}
+.user-grid{padding:12px;display:grid;grid-template-columns:1fr 1fr;gap:12px;}
+.user-card{background:#23264c;border:1px solid rgba(255,138,176,.18);border-radius:14px;overflow:hidden;box-shadow:0 6px 20px rgba(8,10,24,.4);position:relative;}
+.user-card .cover{width:100%;aspect-ratio:1/1.15;display:flex;align-items:flex-end;padding:8px;position:relative;color:#fff;}
+.user-card .cover::before{content:"";position:absolute;inset:0;z-index:0;}
+.user-card.av-1 .cover::before{background:linear-gradient(135deg,#ff8ab0,#7a9eff);}
+.user-card.av-2 .cover::before{background:linear-gradient(135deg,#a8c4ff,#5eead4);}
+.user-card.av-3 .cover::before{background:linear-gradient(135deg,#ffd966,#ff9a3c);}
+.user-card.av-4 .cover::before{background:linear-gradient(135deg,#ff5c8a,#ffd966);}
+.user-card.av-5 .cover::before{background:linear-gradient(135deg,#5eead4,#a8c4ff);}
+.user-card.av-6 .cover::before{background:linear-gradient(135deg,#7a9eff,#ff8ab0);}
+.user-card .cover-inner{position:relative;z-index:1;width:100%;}
+.user-card .top-flags{position:absolute;top:8px;left:8px;display:flex;gap:4px;z-index:2;}
