+/* ===================== 根组件 + 路由分发 ===================== */
+const App = {
+  components:{
+    PageLogin, PageOnboard, PageDiscover, PageMessages, PageMe, PageUser,
+    PageFeed, PageChat, PageRecharge, PageWallet, PageWithdraw, PageVip,
+    PageCall, PageAuth, PageInvite, PageInviteRank, PageInviteStats,
+    PageLanding, PageSettings, GiftPanel, PosterModal, FirstRechargeModal,
+  },
+  setup(){
+    const ROUTES = {
+      '/login': 'PageLogin',
+      '/onboard': 'PageOnboard',
+      '/discover': 'PageDiscover',
+      '/messages': 'PageMessages',
+      '/me': 'PageMe',
+      '/user': 'PageUser',
+      '/feed': 'PageFeed',
+      '/chat': 'PageChat',
+      '/recharge': 'PageRecharge',
+      '/wallet': 'PageWallet',
+      '/withdraw': 'PageWithdraw',
+      '/vip': 'PageVip',
+      '/call': 'PageCall',
+      '/auth': 'PageAuth',
+      '/invite': 'PageInvite',
+      '/landing': 'PageLanding',
+      '/settings': 'PageSettings',
+    }
+    const currentPage = computed(()=>{
+      if(currentRoute.value.startsWith('/invite/rank')) return 'PageInviteRank'
+      if(currentRoute.value.startsWith('/invite/stats')) return 'PageInviteStats'
+      const r = parseRoute(currentRoute.value)
+      if(!store.loggedIn && r.path!=='/login' && r.path!=='/landing'){
+        setTimeout(()=>go('/login'),0)
+        return 'PageLogin'
+      }
+      if(store.loggedIn && !store.onboarded && r.path!=='/onboard' && r.path!=='/login'){
+        setTimeout(()=>go('/onboard'),0)
+        return 'PageOnboard'
+      }
+      return ROUTES[r.path] || 'PageDiscover'
+    })
+    return {currentPage, uiState}
+  },
+  template:`<div class="phone-shell">
+    <component :is="currentPage" />
+    <gift-panel v-if="uiState.giftPanel" />
+    <poster-modal v-if="uiState.poster" />
